@startuml

class Artisan {
  salaire
  coordonnee
  getPaye()
}

class Travailler {
  nbHeure
  debMission
  finMission
  calculerPaye()
}

class Chantier {
  dateD
  dateF
  adresse
  getAdresse()
  affecterArtisan()
}

Artisan "1..*" -- "0..*" Chantier
(Artisan, Chantier) .. Travailler

@enduml
